#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 10
#define INF 1000000000
int min(int a, int b) { return a < b ? a : b; }
int abs(int a) { return a < 0 ? -a : a; }
int main() {
    int T, n, m, i, j, k, l, x, y, z, t, u, v, w;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &m);
        char grid[n][m];
        for (i = 0; i < n; i++) scanf("%s", grid[i]);
        int dx[] = {-1, 0, 1, 0}, dy[] = {0, -1, 0, 1};
        int dist[n][m][n][m];
        for (i = 0; i < n; i++) for (j = 0; j < m; j++) for (k = 0; k < n; k++) for (l = 0; l < m; l++) dist[i][j][k][l] = INF;
        for (i = 0; i < n; i++) for (j = 0; j < m; j++) if (grid[i][j] == '*') {
            dist[i][j][i][j] = 0;
            int q[n * m * n * m][4], qh = 0, qt = 0;
            q[qt][0] = i, q[qt][1] = j, q[qt][2] = i, q[qt][3] = j, qt++;
            while (qh < qt) {
                x = q[qh][0], y = q[qh][1], z = q[qh][2], t = q[qh][3], qh++;
                for (u = 0; u < 4; u++) {
                    int nx = x + dx[u], ny = y + dy[u], nz = z + dx[u], nt = t + dy[u];
                    if (nx >= 0 && nx < n && ny >= 0 && ny < m && nz >= 0 && nz < n && nt >= 0 && nt < m && grid[nx][ny] == '*' && grid[nz][nt] == '*') {
                        if (dist[nx][ny][nz][nt] > dist[x][y][z][t] + 1) {
                            dist[nx][ny][nz][nt] = dist[x][y][z][t] + 1;
                            q[qt][0] = nx, q[qt][1] = ny, q[qt][2] = nz, q[qt][3] = nt, qt++;
                        }
                    }
                }
            }
        }
        int ans = INF;
        for (i = 0; i < n; i++) for (j = 0; j < m; j++) if (grid[i][j] == '*') for (k = 0; k < n; k++) for (l = 0; l < m; l++) if (grid[k][l] == '*') ans = min(ans, dist[i][j][k][l]);
        printf("%d\n", ans);
    }
    return 0;
}

