import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt(), m = scanner.nextInt();
            char[][] grid = new char[n][m];
            for (int i = 0; i < n; i++) grid[i] = scanner.next().toCharArray();
            int[][] dx = {{-1, 0, 1, 0}}, dy[] = {{0, -1, 0, 1}};
            int[][][][] dist = new int[n][m][n][m];
            for (int i = 0; i < n; i++) for (int j = 0; j < m; j++) for (int k = 0; k < n; k++) for (int l = 0; l < m; l++) dist[i][j][k][l] = Integer.MAX_VALUE;
            for (int i = 0; i < n; i++) for (int j = 0; j < m; j++) if (grid[i][j] == '*') {
                dist[i][j][i][j] = 0;
                Queue<int[]> q = new LinkedList<>();
                q.add(new int[]{i, j, i, j});
                while (!q.isEmpty()) {
                    int[] arr = q.poll();
                    int x = arr[0], y = arr[1], z = arr[2], t = arr[3];
                    for (int u = 0; u < 4; u++) {
                        int nx = x + dx[0][u], ny = y + dy[0][u], nz = z + dx[0][u], nt = t + dy[0][u];
                        if (nx >= 0 && nx < n && ny >= 0 && ny < m && nz >= 0 && nz < n && nt >= 0 && nt < m && grid[nx][ny] == '*' && grid[nz][nt] == '*') {
                            if (dist[nx][ny][nz][nt] > dist[x][y][z][t] + 1) {
                                dist[nx][ny][nz][nt] = dist[x][y][z][t] + 1;
                                q.add(new int[]{nx, ny, nz, nt});
                            }
                        }
                    }
                }
            }
            int ans = Integer.MAX_VALUE;
            for (int i = 0; i < n; i++) for (int j = 0; j < m; j++) if (grid[i][j] == '*') for (int k = 0; k < n; k++) for (int l = 0; l < m; l++) if (grid[k][l] == '*') ans = Math.min(ans, dist[i][j][k][l]);
            System.out.println(ans);
        }
    }
}

