const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', function(line) {
    input.push(line);
}).on('close', function() {
    let T = +input[0];
    let i = 1;
    while (T--) {
        let [n, m] = input[i++].split(' ').map(Number);
        let grid = input.slice(i, i + n).map(str => str.trim().split(''));
        i += n;
        let dx = [-1, 0, 1, 0], dy = [0, -1, 0, 1];
        let dist = Array(n).fill().map(() => Array(m).fill().map(() => Array(n).fill().map(() => Array(m).fill(Infinity))));
        for (let x = 0; x < n; x++) {
            for (let y = 0; y < m; y++) {
                if (grid[x][y] === '*') {
                    dist[x][y][x][y] = 0;
                    let q = [[x, y, x, y]];
                    while (q.length) {
                        let [x, y, z, t] = q.shift();
                        for (let u = 0; u < 4; u++) {
                            let nx = x + dx[u], ny = y + dy[u], nz = z + dx[u], nt = t + dy[u];
                            if (nx >= 0 && nx < n && ny >= 0 && ny < m && nz >= 0 && nz < n && nt >= 0 && nt < m && grid[nx][ny] === '*' && grid[nz][nt] === '*') {
                                if (dist[nx][ny][nz][nt] > dist[x][y][z][t] + 1) {
                                    dist[nx][ny][nz][nt] = dist[x][y][z][t] + 1;
                                    q.push([nx, ny, nz, nt]);
                                }
                            }
                        }
                    }
                }
            }
        }
        let ans = Infinity;
        for (let x = 0; x < n; x++) {
            for (let y = 0; y < m; y++) {
                if (grid[x][y] === '*') {
                    for (let z = 0; z < n; z++) {
                        for (let t = 0; t < m; t++) {
                            if (grid[z][t] === '*') {
                                ans = Math.min(ans, dist[x][y][z][t]);
                            }
                        }
                    }
                }
            }
        }
        console.log(ans);
    }
});

